@page "/board"
@using sv_13e73ad478a647519e94dacaf68de7bf.Services
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="In Progress"
                     Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />

        <BoardColumn ColumnName="Done"
                     Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="HandleAddTask" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.First(t => t.Id == args.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = args.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        // The service may not set the status to the column's status, so ensure it matches
        allTasks.Add(created with { Status = args.Status });
    }
}

