@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? error;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee) || string.IsNullOrWhiteSpace(priority))
        {
            error = "Title, assignee, and priority are required.";
            return;
        }

        error = null;
        saving = true;
        try
        {
            await OnSave.InvokeAsync((title, assignee, priority, dueDate));
            title = "";
            assignee = "";
            priority = "";
            dueDate = DateTime.Today.AddDays(7);
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel()
    {
        error = null;
        await OnCancel.InvokeAsync();
    }
}
"}

